import React, { useEffect, useState } from "react";
import axios from "axios";
import ItemCard from "../components/ItemCard";
<button
  onClick={() => window.location.reload()}
  className="bg-gray-500 text-white px-4 py-2 rounded mb-6"
>
  ⬅ Back
</button>

const CRUDPage = ({ db }) => {
  const [items, setItems] = useState([]);
  const [form, setForm] = useState({ name: "", description: "", price: "" });

  const fetchItems = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/items");
      setItems(res.data);
    } catch (err) {
      console.error("Failed to fetch items", err);
    }
  };

  useEffect(() => {
    fetchItems();
  }, []);
  const [editingId, setEditingId] = useState(null);
  const deleteItem = async (id) => {

    await axios.delete(`http://localhost:5000/api/items/${id}`);

    fetchItems();

  };
  const editItem = (item) => {

    setForm({
      name: item.name,
      description: item.description,
      price: item.price
    });

    setEditingId(item.id || item._id);

  };


  const handleSubmit = async (e) => {

    e.preventDefault();

    if (editingId) {

      await axios.put(
        `http://localhost:5000/api/items/${editingId}`,
        form
      );

      setEditingId(null);

    } else {

      await axios.post(
        "http://localhost:5000/api/items",
        form
      );

    }

    setForm({ name: "", description: "", price: "" });

    fetchItems();

  };
  return (
    <div className="max-w-6xl mx-auto">
      <h1 className="text-4xl font-bold text-gray-800 mb-8">
        CRUD Operations ({db.toUpperCase()})
      </h1>

      {/* Form */}
      <form onSubmit={handleSubmit} className="flex flex-col md:flex-row gap-4 mb-8">
        <input
          type="text"
          placeholder="Name"
          value={form.name}
          onChange={(e) => setForm({ ...form, name: e.target.value })}
          className="border border-gray-300 p-3 rounded-lg flex-1"
          required
        />
        <input
          type="text"
          placeholder="Description"
          value={form.description}
          onChange={(e) => setForm({ ...form, description: e.target.value })}
          className="border border-gray-300 p-3 rounded-lg flex-1"
          required
        />
        <input
          type="number"
          placeholder="Price"
          value={form.price}
          onChange={(e) => setForm({ ...form, price: e.target.value })}
          className="border border-gray-300 p-3 rounded-lg w-32"
          required
        />
        <button
          type="submit"
          className="bg-green-500 text-white px-6 py-3 rounded-lg font-semibold hover:bg-green-600 transition"
        >
          Add Item
        </button>
      </form>

      {/* Items List */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {items.map((item) => (
          <ItemCard
            key={item.id || item._id}
            item={item}
            onDelete={deleteItem}
            onEdit={editItem}
          />
        ))}
      </div>
    </div>
  );
};

export default CRUDPage;
